ss() const;\n109: \n110:   bool in_undo_mark() const;\n111: \n112:   // Update the perf data counter for concurrent mark.\n113:   void update_threads_cpu_time();\n114: };\n115: \n116: #endif // SHARE_GC_G1_G1CONCURRENTMARKTHREAD_HPP\n117: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/jdk--742e735d@b394eab7f7a9ef928dbbcac1e27e0a0b1577894a/-/blob/src/hotspot/share/gc/g1/g1ConcurrentMarkThread.hpp"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /*
