33: // The concurrent mark thread triggers the various steps of the concurrent marking
34: // cycle, including various marking cleanup.
35: class G1ConcurrentMarkThread: public ConcurrentGCThread {
36:   friend class VMStructs;
37: 
38:   double _vtime_start;  // Initial virtual time.
39:   double _vtime_accum;  // Accumulated virtual time.
40: 
41:   G1ConcurrentMark* _cm;
42: 
43:   enum ServiceState : uint {
44:     Idle,
45:     FullMark,
46:     UndoMark
47:   };
48: 
49:   volatile ServiceState _state;
50: 
51:   // Wait for next cycle. Returns the command passed over.
52:   bool wait_for_next_cycle();
53: 
54:   bool mark_loop_needs_restart() const;
55: 
56:   // Phases and subphases for the full concurrent marking cycle in order.
57:   //
58:   // All these methods return true if the marking should be aborted.
59:   bool phase_clear_cld_claimed_marks();
60:   bool phase_scan_root_regions();
61: 
62:   bool phase_mark_loop();
63:   bool subphase_mark_from_roots();
64:   bool subphase_preclean();
65:   bool subphase_delay_to_keep_mmu_before_remark();
66:   bool subphase_remark();
67: 
68:   bool phase_rebuild_and_scrub();
69:   bool phase_delay_to_keep_mmu_before_cleanup();
70:   bool phase_cleanup();
71:   bool phase_clear_bitmap_for_next_mark();
72: 
73:   void concurrent_cycle_start();
74: 
75:   void concurrent_mark_cycle_do();
76:   void concurrent_undo_cycle_do();
77: 
78:   void concurrent_cycle_end(bool mark_cycle_completed);
79: 
80:   // Delay pauses to meet MMU.
81:   void delay_to_keep_mmu(bool remark);
82:   double mmu_delay_end(G1Policy* policy, bool remark);
83: 
84:   void run_service();
85:   void stop_service();
86: 
87:  public:
88:   // Constructor
89:   G1ConcurrentMarkThread(G1ConcurrentMark* cm);
90: 
91:   // Total virtual time so far for this thread and concurrent marking tasks.
92:   double vtime_accum();
93:   // Marking virtual time so far this thread and concurrent marking tasks.
94:   double vtime_mark_accum();
95: 
96:   G1ConcurrentMark* cm() { return _cm; }
97: 
98:   void set_idle();
99:   void start_full_mark();
100:   void start_undo_mark();
101: 
102:   bool idle() const;
103:   // Returns true from the moment a concurrent cycle is
104:   // initiated (during the concurrent start pause when started() is set)
105:   // to the moment when the cycle completes (just after the next
106:   // marking bitmap has been cleared and in_progress() is
107:   // cleared).
108:   bool in_progress() const;
109: 
110:   bool in_undo_mark() const;
111: 
112:   // Update the perf data counter for concurrent mark.
113:   void update_threads_cpu_time();
114: };
