on set candidates, i.e. region groups that could/should be evacuated soon.\n192: //\n193: // These candidate groups are tracked in two list of region groups, sorted by decreasing\n194: // \"gc efficiency\".\n195: //\n196: // * from_marking_groups: the set of region groups selected by concurrent marking to be\n197: //                        evacuated to keep overall heap occupancy stable.\n198: //                        They are guaranteed to be evacuated and cleared out during\n199: //                        the mixed phase.\n200: //\n201: // * retained_groups: set of region groups selected for evacuation during evacuation\n202: //                    failure.\n203: //                    Any young collection will try to evacuate them.\n204: //\n205: class G1CollectionSetCandidates : public CHeapObj\u003cmtGC\u003e {\n206: \n207:   enum class CandidateOrigin : uint8_t {\n208:     Invalid,\n209:     Marking,                   // This region has been determined as candidate by concurrent marking.\n210:     Retained,                  // This region has been added because it has been retained after evacuation.\n211:     Verify                     // Special value for verification.\n212:   };\n213: \n214:   CandidateOrigin* _contains_map;\n215:   G1CSetCandidateGroupList _from_marking_groups; // Set of regions selected by concurrent marking.\n216:   // Set of regions retained due to evacuation failure. Groups added to this list\n217:   // should contain only one region each, making it easier to evacuate retained regions\n218:   // in any young collection.\n219:   G1CSetCandidateGroupList _retained_groups;\n220:   uint _max_regions;\n221: \n222:   // The number of regions from the last merge of candidates from the marking.\n223:   uint _last_marking_candidates_length;\n224: \n225:   bool is_from_marking(G1HeapRegion* r) const;\n226: \n227: public:\n228:   G1CollectionSetCandidates();\n229:   ~G1CollectionSetCandidates();\n230: \n231:   G1CSetCandidateGroupList\u0026 from_marking_groups() { return _from_marking_groups; }\n232:   G1CSetCandidateGroupList\u0026 retained_groups() { return _retained_groups; }\n233: \n234:   void initialize(uint max_regions);\n235: \n236:   void clear();\n237: \n238:   // Merge collection set candidates from marking into the current marking list\n239:   // (which needs to be empty).\n240:   void set_candidates_from_marking(G1CollectionSetCandidateInfo* candidate_infos,\n241:                                    uint num_infos);\n242:   // The most recent length of the list that had been merged last via\n243:   // set_candidates_from_marking(). Used for calculating minimum collection set\n244:   // regions.\n245:   uint last_marking_candidates_length() const { return _last_marking_candidates_length; }\n246: \n247:   void sort_by_efficiency();\n248: \n249:   void sort_marking_by_efficiency();\n250: \n251:   // Add the given region to the set of retained regions without regards to the\n252:   // gc efficiency sorting. The retained regions must be re-sorted manually later.\n253:   void add_retained_region_unsorted(G1HeapRegion* r);\n254:   // Remove the given groups from the candidates. All given regions must be part\n255:   // of the candidates.\n256:   void remove(G1CSetCandidateGroupList* other);\n257: \n258:   bool contains(const G1HeapRegion* r) const;\n259: \n260:   const char* get_short_type_str(const G1HeapRegion* r) const;\n261: \n262:   bool is_empty() const;\n263: \n264:   bool has_more_marking_candidates() const;\n265:   uint marking_regions_length() const;\n266:   uint retained_regions_length() const;\n267: \n268: private:\n269:   void verify_helper(G1CSetCandidateGroupList* list, uint\u0026 from_marking, CandidateOrigin* verify_map) PRODUCT_RETURN;\n270: \n271: public:\n272:   void verify() PRODUCT_RETURN;\n273: \n274:   uint length() const { return marking_regions_length() + retained_regions_length(); }\n275: \n276:   template\u003ctypename Func\u003e\n277:   void iterate_regions(Func\u0026\u0026 f) const;\n278: };\n279: \n280: #endif /* SHARE_GC_G1_G1COLLECTIONSETCANDIDATES_HPP */\n281: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/jdk--742e735d@b394eab7f7a9ef928dbbcac1e27e0a0b1577894a/-/blob/src/hotspot/share/gc/g1/g1CollectionSetCandidates.hpp"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /*
