40: struct G1CollectionSetCandidateInfo {
41:   G1HeapRegion* _r;
42:   uint _num_unreclaimed;          // Number of GCs this region has been found unreclaimable.
43: 
44:   G1CollectionSetCandidateInfo() : G1CollectionSetCandidateInfo(nullptr) { }
45:   G1CollectionSetCandidateInfo(G1HeapRegion* r) : _r(r), _num_unreclaimed(0) { }
46: 
47:   bool update_num_unreclaimed() {
48:     ++_num_unreclaimed;
49:     return _num_unreclaimed < G1NumCollectionsKeepPinned;
50:   }
