55: // G1CSetCandidateGroup groups candidate regions that will be selected for evacuation at the same time.
56: // Grouping occurs both for candidates from marking or regions retained during evacuation failure, but a group
57: // can not contain regions from both types of regions.
58: //
59: // Humongous objects are excluded from the candidate groups because regions associated with these
60: // objects are never selected for evacuation.
61: //
62: // All regions in the group share a G1CardSet instance, which tracks remembered set entries for the
63: // regions in the group. We do not have track to cross-region references for regions that are in the
64: // same group saving memory.
65: class G1CSetCandidateGroup : public CHeapObj<mtGCCardSet>{
66:   GrowableArray<G1CollectionSetCandidateInfo> _candidates;
67: 
68:   G1CardSetMemoryManager _card_set_mm;
69: 
70:   // The set of cards in the Java heap
71:   G1CardSet _card_set;
72: 
73:   size_t _reclaimable_bytes;
74:   double _gc_efficiency;
75: 
76:   // The _group_id is primarily used when printing out per-region liveness information,
77:   // making it easier to associate regions with their assigned G1CSetCandidateGroup, if any.
78:   // Note:
79:   // * _group_id 0 is reserved for special G1CSetCandidateGroups that hold only a single region,
80:   //    such as G1CSetCandidateGroups for retained regions.
81:   // * _group_id 1 is reserved for the G1CSetCandidateGroup that contains all young regions.
82:   const uint _group_id;
83:   static uint _next_group_id;
84: public:
85:   G1CSetCandidateGroup();
86:   G1CSetCandidateGroup(G1CardSetConfiguration* config, G1MonotonicArenaFreePool* card_set_freelist_pool, uint group_id);
87:   ~G1CSetCandidateGroup() {
88:     assert(length() == 0, "post condition!");
89:   }
90: 
91:   void add(G1HeapRegion* hr);
92:   void add(G1CollectionSetCandidateInfo& hr_info);
93: 
94:   uint length() const { return (uint)_candidates.length(); }
95: 
96:   G1CardSet* card_set() { return &_card_set; }
97:   const G1CardSet* card_set() const { return &_card_set; }
98: 
99:   uint group_id() const { return _group_id; }
100: 
101:   void calculate_efficiency();
102: 
103:   size_t liveness() const;
104:   // Comparison function to order regions in decreasing GC efficiency order. This
105:   // will cause regions with a lot of live objects and large remembered sets to end
106:   // up at the end of the list.
107:   static int compare_gc_efficiency(G1CSetCandidateGroup** gr1, G1CSetCandidateGroup** gr2);
108: 
109:   static int compare_reclaimble_bytes(G1CollectionSetCandidateInfo* ci1, G1CollectionSetCandidateInfo* ci2);
110: 
111:   double gc_efficiency() const { return _gc_efficiency; }
112: 
113:   G1HeapRegion* region_at(uint i) const { return _candidates.at(i)._r; }
114: 
115:   G1CollectionSetCandidateInfo* at(uint i) { return &_candidates.at(i); }
116: 
117:   double predict_group_total_time_ms() const;
118: 
119:   G1MonotonicArenaMemoryStats card_set_memory_stats() const {
120:     return _card_set_mm.memory_stats();
121:   }
122: 
123:   void clear(bool uninstall_group_cardset = false);
124: 
125:   G1CSetCandidateGroupIterator begin() const {
126:     return _candidates.begin();
127:   }
128: 
129:   G1CSetCandidateGroupIterator end() const {
130:     return _candidates.end();
131:   }
132: 
133:   static void reset_next_group_id() {
134:     _next_group_id = 2;
135:   }
136: };
