140: class G1CSetCandidateGroupList {
141:   GrowableArray<G1CSetCandidateGroup*> _groups;
142:   volatile uint _num_regions;
143: 
144: public:
145:   G1CSetCandidateGroupList();
146:   void append(G1CSetCandidateGroup* group);
147: 
148:   // Delete all groups from the list. The cardset cleanup for regions within the
149:   // groups could have been done elsewhere (e.g. when adding groups to the
150:   // collection set or to retained regions). The uninstall_group_cardset is set to
151:   // true if cleanup needs to happen as we clear the groups from the list.
152:   void clear(bool uninstall_group_cardset = false);
153: 
154:   G1CSetCandidateGroup* at(uint index);
155: 
156:   uint length() const { return (uint)_groups.length(); }
157: 
158:   uint num_regions() const { return _num_regions; }
159: 
160:   void remove_selected(uint count, uint num_regions);
161: 
162:   // Removes any candidate groups stored in this list and also in the other list. The other
163:   // list may only contain candidate groups in this list, sorted by gc efficiency. It need
164:   // not be a prefix of this list.
165:   // E.g. if this list is "A B G H", the other list may be "A G H", but not "F" (not in
166:   // this list) or "A H G" (wrong order).
167:   void remove(G1CSetCandidateGroupList* other);
168: 
169:   void prepare_for_scan();
170: 
171:   void sort_by_efficiency();
172: 
173:   GrowableArray<G1CSetCandidateGroup*>*  groups() {
174:     return &_groups;
175:   }
176: 
177:   void verify() const PRODUCT_RETURN;
178: 
179:   G1CSetCandidateGroupListIterator begin() const {
180:     return _groups.begin();
181:   }
182: 
183:   G1CSetCandidateGroupListIterator end() const {
184:     return _groups.end();
185:   }
186: 
187:   template<typename Func>
188:   void iterate(Func&& f) const;
189: };
