115: void G1ConcurrentMarkThread::run_service() {
116:   _vtime_start = os::elapsedVTime();
117: 
118:   while (wait_for_next_cycle()) {
119:     assert(in_progress(), "must be");
120: 
121:     GCIdMark gc_id_mark;
122:     FormatBuffer<128> title("Concurrent %s Cycle", _state == FullMark ? "Mark" : "Undo");
123:     GCTraceConcTime(Info, gc) tt(title);
124: 
125:     concurrent_cycle_start();
126: 
127:     if (_state == FullMark) {
128:       concurrent_mark_cycle_do();
129:     } else {
130:       assert(_state == UndoMark, "Must do undo mark but is %d", _state);
131:       concurrent_undo_cycle_do();
132:     }
133: 
134:     concurrent_cycle_end(_state == FullMark && !_cm->has_aborted());
135: 
136:     _vtime_accum = (os::elapsedVTime() - _vtime_start);
137: 
138:     update_threads_cpu_time();
139:   }
140:   _cm->root_regions()->cancel_scan();
141: }
