144:   if (in_progress()) {
145:     // We are not allowed to abort the marking threads during root region scan.
146:     // Needs to be done separately.
147:     _cm->root_region_scan_abort_and_wait();
148: 
149:     _cm->abort_marking_threads();
150:   }
151: 
152:   MutexLocker ml(CGC_lock, Mutex::_no_safepoint_check_flag);
153:   CGC_lock->notify_all();
