178: bool G1ConcurrentMarkThread::phase_mark_loop() {
179:   Ticks mark_start = Ticks::now();
180:   log_info(gc, marking)("Concurrent Mark");
181: 
182:   for (uint iter = 1; true; ++iter) {
183:     // Subphase 1: Mark From Roots.
184:     if (subphase_mark_from_roots()) return true;
185: 
186:     // Subphase 2: Preclean (optional)
187:     if (G1UseReferencePrecleaning) {
188:       if (subphase_preclean()) return true;
189:     }
190: 
191:     // Subphase 3: Wait for Remark.
192:     if (subphase_delay_to_keep_mmu_before_remark()) return true;
193: 
194:     // Subphase 4: Remark pause
195:     if (subphase_remark()) return true;
196: 
197:     // Check if we need to restart the marking loop.
198:     if (!mark_loop_needs_restart()) break;
199: 
200:     log_info(gc, marking)("Concurrent Mark Restart for Mark Stack Overflow (iteration #%u)",
201:                           iter);
202:   }
203: 
204:   log_info(gc, marking)("Concurrent Mark %.3fms",
205:                         (Ticks::now() - mark_start).seconds() * 1000.0);
206: 
207:   return false;
208: }
