ion when adding a region.\n179:   void add_young_region_common(G1HeapRegion* hr);\n180: \n181:   // Add the given old region to the head of the current collection set.\n182:   void add_old_region(G1HeapRegion* hr);\n183: \n184:   void prepare_optional_group(G1CSetCandidateGroup* gr, uint cur_index);\n185: \n186:   void add_group_to_collection_set(G1CSetCandidateGroup* gr);\n187: \n188:   void add_region_to_collection_set(G1HeapRegion* r);\n189: \n190:   double select_candidates_from_marking(double time_remaining_ms);\n191: \n192:   void select_candidates_from_retained(double time_remaining_ms);\n193: \n194:   // Select regions for evacuation from the optional candidates given the remaining time\n195:   // and return the number  of actually selected regions.\n196:   uint select_optional_collection_set_regions(double time_remaining_ms);\n197:   double select_candidates_from_optional_groups(double time_remaining_ms, uint\u0026 num_regions_selected);\n198: \n199:   // Finalize the young part of the initial collection set. Relabel survivor regions\n200:   // as Eden and calculate a prediction on how long the evacuation of all young regions\n201:   // will take.\n202:   double finalize_young_part(double target_pause_time_ms, G1SurvivorRegions* survivors);\n203:   // Perform any final calculations on the incremental collection set fields before we\n204:   // can use them.\n205:   void finalize_incremental_building();\n206: \n207:   // Select the regions comprising the initial and optional collection set from marking\n208:   // and retained collection set candidates.\n209:   void finalize_old_part(double time_remaining_ms);\n210: \n211:   // Iterate the part of the collection set given by the offset and length applying the given\n212:   // G1HeapRegionClosure. The worker_id will determine where in the part to start the iteration\n213:   // to allow for more efficient parallel iteration.\n214:   void iterate_part_from(G1HeapRegionClosure* cl,\n215:                          G