::ScanHR, G1GCPhaseTimes::ScanHRScannedCards) +\n775:                                  phase_times()-\u003esum_thread_work_items(G1GCPhaseTimes::OptScanHR, G1GCPhaseTimes::ScanHRScannedCards);\n776: \n777:   double merge_logged_cards_time = average_time_ms(G1GCPhaseTimes::MergeLB) +\n778:                                    phase_times()-\u003ecur_distribute_log_buffers_time_ms();\n779: \n780:   // Approximate the time spent processing cards from log buffers by scaling\n781:   // the total processing time by the ratio of logged cards to total cards\n782:   // processed.  There might be duplicate cards in different log buffers,\n783:   // leading to an overestimate.  That effect should be relatively small\n784:   // unless there are few cards to process, because cards in buffers are\n785:   // dirtied to limit duplication.  Also need to avoid scaling when both\n786:   // counts are zero, which happens especially during early GCs.  So ascribe\n787:   // all of the time to the logged cards unless there are more total cards.\n788:   if (logged_dirty_cards \u003e= scan_heap_roots_cards) {\n789:     return all_cards_processing_time + merge_logged_cards_time;\n790:   }\n791:   return (all_cards_processing_time * logged_dirty_cards / scan_heap_roots_cards) + merge_logged_cards_time;\n792: }\n793: \n794: // Anything below that is considered to be zero\n795: #define MIN_TIMER_GRANULARITY 0.0000001\n796: \n797: void G1Policy::record_young_collection_end(bool concurrent_operation_is_full_mark, bool allocation_failure) {\n798:   G1GCPhaseTimes* p = phase_times();\n799: \n800:   double start_time_sec = phase_times()-\u003ecur_collection_start_sec();\n801: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/jdk--742e735d@b394eab7f7a9ef928dbbcac1e27e0a0b1577894a/-/blob/src/hotspot/share/gc/g1/g1Policy.cpp%3FL744-800"}", "annotations": null, "meta": null}], "structuredContent": {"content": "744: 
745: bool G1Policy::need_to_start_conc_mark(const char* source, size_t alloc_word_size) {
746:   if (about_to_start_mixed_phase()) {
747:     return false;
748:   }
749: 
750:   size_t marking_initiating_used_threshold = _ihop_control->get_conc_mark_start_threshold();
751: 
752:   size_t cur_used_bytes = _g1h->non_young_capacity_bytes();
753:   size_t alloc_byte_size = alloc_word_size * HeapWordSize;
754:   size_t marking_request_bytes = cur_used_bytes + alloc_byte_size;
755: 
756:   bool result = false;
757:   if (marking_request_bytes > marking_initiating_used_threshold) {
758:     result = collector_state()->in_young_only_phase();
759:     log_debug(gc, ergo, ihop)("%s occupancy: %zuB allocation request: %zuB threshold: %zuB (%1.2f) source: %s",
760:                               result ? "Request concurrent cycle initiation (occupancy higher than threshold)" : "Do not request concurrent cycle initiation (still doing mixed collections)",
761:                               cur_used_bytes, alloc_byte_size, marking_initiating_used_threshold, (double) marking_initiating_used_threshold / _g1h->capacity() * 100, source);
762:   }
763:   return result;
