771: double G1Policy::logged_cards_processing_time() const {
772:   double all_cards_processing_time = average_time_ms(G1GCPhaseTimes::ScanHR) + average_time_ms(G1GCPhaseTimes::OptScanHR);
773:   size_t logged_dirty_cards = phase_times()->sum_thread_work_items(G1GCPhaseTimes::MergeLB, G1GCPhaseTimes::MergeLBDirtyCards);
774:   size_t scan_heap_roots_cards = phase_times()->sum_thread_work_items(G1GCPhaseTimes::ScanHR, G1GCPhaseTimes::ScanHRScannedCards) +
775:                                  phase_times()->sum_thread_work_items(G1GCPhaseTimes::OptScanHR, G1GCPhaseTimes::ScanHRScannedCards);
776: 
777:   double merge_logged_cards_time = average_time_ms(G1GCPhaseTimes::MergeLB) +
778:                                    phase_times()->cur_distribute_log_buffers_time_ms();
779: 
780:   // Approximate the time spent processing cards from log buffers by scaling
781:   // the total processing time by the ratio of logged cards to total cards
782:   // processed.  There might be duplicate cards in different log buffers,
783:   // leading to an overestimate.  That effect should be relatively small
784:   // unless there are few cards to process, because cards in buffers are
785:   // dirtied to limit duplication.  Also need to avoid scaling when both
786:   // counts are zero, which happens especially during early GCs.  So ascribe
787:   // all of the time to the logged cards unless there are more total cards.
788:   if (logged_dirty_cards >= scan_heap_roots_cards) {
789:     return all_cards_processing_time + merge_logged_cards_time;
790:   }
791:   return (all_cards_processing_time * logged_dirty_cards / scan_heap_roots_cards) + merge_logged_cards_time;
792: }
