{"meta": null, "content": [{"type": "text", "text": "{"content":"1500: void G1ConcurrentMark::compute_new_sizes() {\n1501:   MetaspaceGC::compute_new_size();\n1502: \n1503:   // Cleanup will have freed any regions completely full of garbage.\n1504:   // Update the soft reference policy with the new heap occupancy.\n1505:   Universe::heap()-\u003eupdate_capacity_and_used_at_gc();\n1506: \n1507:   // We reclaimed old regions so we should calculate the sizes to make\n1508:   // sure we update the old gen/space data.\n1509:   _g1h-\u003emonitoring_support()-\u003eupdate_sizes();\n1510: }\n1511: \n1512: void G1ConcurrentMark::cleanup() {\n1513:   assert_at_safepoint_on_vm_thread();\n1514: \n1515:   // If a full collection has happened, we shouldn't do this.\n1516:   if (has_aborted()) {\n1517:     return;\n1518:   }\n1519: \n1520:   G1Policy* policy = _g1h-\u003epolicy();\n1521:   policy-\u003erecord_concurrent_mark_cleanup_start();\n1522: \n1523:   double start = os::elapsedTime();\n1524: \n1525:   verify_during_pause(G1HeapVerifier::G1VerifyCleanup, VerifyLocation::CleanupBefore);\n1526: \n1527:   if (needs_remembered_set_rebuild()) {\n1528:     // Update the remset tracking information as well as marking all regions\n1529:     // as fully parsable.\n1530:     GCTraceTime(Debug, gc, phases) debug(\"Update Remembered Set Tracking After Rebuild\", _gc_timer_cm);\n1531:     G1UpdateRegionsAfterRebuild cl(_g1h);\n1532:     _g1h-\u003eheap_region_iterate(\u0026cl);\n1533:   } else {\n1534:     log_debug(gc, phases)(\"No Remembered Sets to update after rebuild\");\n1535:   }\n1536: \n1537:   verify_during_pause(G1HeapVerifier::G1VerifyCleanup, VerifyLocation::CleanupAfter);\n1538: \n1539:   // Local statistics\n1540:   _cleanup_times.add((os::elapsedTime() - start) * 1000.0);\n1541: \n1542:   {\n1543:     GCTraceTime(Debug, gc, phases) debug(\"Finalize Concurrent Mark Cleanup\", _gc_timer_cm);\n1544:     policy-\u003erecord_concurrent_mark_cleanup_end(needs_remembered_set_rebuild());\n1545:   }\n1546: }\n1547: \n1548: // 'Keep Alive' oop closure used by both serial parallel reference processing.\n1549: // Uses the G1CMTask associated with a worker thread (for serial reference\n1550: // processing the G1CMTask for worker 0 is used) to preserve (mark) and\n1551: // trace referent objects.\n1552: //\n1553: // Using the G1CMTask and embedded local queues avoids having the worker\n1554: // threads operating on the global mark stack. This reduces the risk\n1555: // of overflowing the stack - which we would rather avoid at this late\n1556: // state. Also using the tasks' local queues removes the potential\n1557: // of the workers interfering with each other that could occur if\n1558: // operating on the global stack.\n1559: \n1560: class G1CMKeepAliveAndDrainClosure : public OopClosure {\n1561:   G1ConcurrentMark* _cm;\n1562:   G1CMTask*         _task;\n1563:   uint              _ref_counter_limit;\n1564:   uint              _ref_counter;\n1565:   bool              _is_serial;\n1566: public:\n1567:   G1CMKeepAliveAndDrainClosure(G1ConcurrentMark* cm, G1CMTask* task, bool is_serial) :\n1568:     _cm(cm), _task(task), _ref_counter_limit(G1RefProcDrainInterval),\n1569:     _ref_counter(_ref_counter_limit), _is_serial(is_serial) {\n1570:     assert(!_is_serial || _task-\u003eworker_id() == 0, \"only task 0 for serial code\");\n1571:   }\n1572: \n1573:   virtual void do_oop(narrowOop* p) { do_oop_work(p); }\n1574:   virtual void do_oop(      oop* p) { do_oop_work(p); }\n1575: \n1576:   template \u003cclass T\u003e void do_oop_work(T* p) {\n1577:     if (_cm-\u003ehas_overflown()) {\n1578:       return;\n1579:     }\n1580:     if (!_task-\u003edeal_with_reference(p)) {\n1581:       // We did not add anything to the mark bitmap (or mark stack), so there is\n1582:       // no point trying to drain it.\n1583:       return;\n1584:     }\n1585:     _ref_counter--;\n1586: \n1587:     if (_ref_counter == 0) {\n1588:       // We have dealt with _ref_counter_limit references, pushing them\n1589:       // and objects reachable from them on to the local stack (and\n1590:       // possibly the global stack). Call G1CMTask::do_marking_step() to\n1591:       // process these entries.\n1592:       //\n1593:       // We call G1CMTask::do_marking_step() in a loop, which we'll exit if\n1594:       // there's nothing more to do (i.e. we're done with the entries that\n1595:       // were pushed as a result of the G1CMTask::deal_with_reference() calls\n1596:       // above) or we overflow.\n1597:       //\n1598:       // Note: G1CMTask::do_marking_step() can set the G1CMTask::has_aborted()\n1599:       // flag while there may still be some work to do. (See the comment at\n1600:       // the beginning of G1CMTask::do_marking_step() for those conditions -\n1601: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/jdk--742e735d@b394eab7f7a9ef928dbbcac1e27e0a0b1577894a/-/blob/src/hotspot/share/gc/g1/g1ConcurrentMark.cpp%3FL1500-1600"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1500: void G1ConcurrentMark::compute_new_sizes() {
