1380: void G1ConcurrentMark::remark() {
1381:   assert_at_safepoint_on_vm_thread();
1382: 
1383:   // If a full collection has happened, we should not continue. However we might
1384:   // have ended up here as the Remark VM operation has been scheduled already.
1385:   if (has_aborted()) {
1386:     return;
1387:   }
1388: 
1389:   G1Policy* policy = _g1h->policy();
1390:   policy->record_concurrent_mark_remark_start();
1391: 
1392:   double start = os::elapsedTime();
1393: 
1394:   verify_during_pause(G1HeapVerifier::G1VerifyRemark, VerifyLocation::RemarkBefore);
1395: 
1396:   {
1397:     GCTraceTime(Debug, gc, phases) debug("Finalize Marking", _gc_timer_cm);
1398:     finalize_marking();
1399:   }
1400: 
1401:   double mark_work_end = os::elapsedTime();
1402: 
1403:   bool const mark_finished = !has_overflown();
1404:   if (mark_finished) {
1405:     weak_refs_work();
1406: 
1407:     // Unload Klasses, String, Code Cache, etc.
1408:     if (ClassUnloadingWithConcurrentMark) {
1409:       G1CMIsAliveClosure is_alive(this);
1410:       _g1h->unload_classes_and_code("Class Unloading", &is_alive, _gc_timer_cm);
1411:     }
1412: 
1413:     SATBMarkQueueSet& satb_mq_set = G1BarrierSet::satb_mark_queue_set();
1414:     // We're done with marking.
1415:     // This is the end of the marking cycle, we're expected all
1416:     // threads to have SATB queues with active set to true.
1417:     satb_mq_set.set_active_all_threads(false, /* new active value */
1418:                                        true /* expected_active */);
1419: 
1420:     {
1421:       GCTraceTime(Debug, gc, phases) debug("Flush Task Caches", _gc_timer_cm);
1422:       flush_all_task_caches();
1423:     }
1424: 
1425:     // All marking completed. Check bitmap now as we will start to reset TAMSes
1426:     // in parallel below so that we can not do this in the After-Remark verification.
1427:     _g1h->verifier()->verify_bitmap_clear(true /* above_tams_only */);
1428: 
1429:     {
1430:       GCTraceTime(Debug, gc, phases) debug("Select For Rebuild and Reclaim Empty Regions", _gc_timer_cm);
1431: 
1432:       G1UpdateRegionLivenessAndSelectForRebuildTask cl(_g1h, this, _g1h->workers()->active_workers());
1433:       uint const num_workers = MIN2(G1UpdateRegionLivenessAndSelectForRebuildTask::desired_num_workers(_g1h->num_regions()),
1434:                                     _g1h->workers()->active_workers());
1435:       log_debug(gc,ergo)("Running %s using %u workers for %u regions in heap", cl.name(), num_workers, _g1h->num_regions());
1436:       _g1h->workers()->run_task(&cl, num_workers);
1437: 
1438:       log_debug(gc, remset, tracking)("Remembered Set Tracking update regions total %u, selected %u",
1439:                                         _g1h->num_regions(), cl.total_selected_for_rebuild());
1440: 
1441:       _needs_remembered_set_rebuild = (cl.total_selected_for_rebuild() > 0);
1442: 
1443:       if (_needs_remembered_set_rebuild) {
1444:         // Prune rebuild candidates based on G1HeapWastePercent.
1445:         // Improves rebuild time in addition to remembered set memory usage.
1446:         G1CollectionSetChooser::build(_g1h->workers(), _g1h->num_regions(), _g1h->policy()->candidates());
1447:       }
1448:     }
1449: 
1450:     if (log_is_enabled(Trace, gc, liveness)) {
1451:       G1PrintRegionLivenessInfoClosure cl("Post-Marking");
1452:       _g1h->heap_region_iterate(&cl);
1453:     }
1454: 
1455:     // Potentially, some empty-regions have been reclaimed; make this a
1456:     // "collection" so that pending allocation can retry before attempting a
1457:     // GC pause.
1458:     _g1h->increment_total_collections();
1459: 
1460:     _g1h->resize_heap_if_necessary();
1461:     _g1h->uncommit_regions_if_necessary();
1462: 
1463:     compute_new_sizes();
1464: 
1465:     verify_during_pause(G1HeapVerifier::G1VerifyRemark, VerifyLocation::RemarkAfter);
1466: 
1467:     assert(!restart_for_overflow(), "sanity");
1468:     // Completely reset the marking state (except bitmaps) since marking completed.
1469:     reset_at_marking_complete();
1470: 
1471:     G1CollectedHeap::finish_codecache_marking_cycle();
1472: 
1473:     {
1474:       GCTraceTime(Debug, gc, phases) debug("Report Object Count", _gc_timer_cm);
1475:       G1ObjectCountIsAliveClosure is_alive(_g1h);
1476:       _gc_tracer_cm->report_object_count_after_gc(&is_alive, _g1h->workers());
1477:     }
1478:   } else {
1479:     // We overflowed.  Restart concurrent marking.
1480:     _restart_for_overflow = true;
1481: 
1482:     verify_during_pause(G1HeapVerifier::G1VerifyRemark, VerifyLocation::RemarkOverflow);
1483: 
1484:     // Clear the marking state because we will be restarting
1485:     // marking due to overflowing the global mark stack.
1486:     reset_marking_for_restart();
1487:   }
1488: 
1489:   // Statistics
1490:   double now = os::elapsedTime();
1491:   _remark_mark_times.add((mark_work_end - start) * 1000.0);
1492:   _remark_weak_ref_times.add((now - mark_work_end) * 1000.0);
1493:   _remark_times.add((now - start) * 1000.0);
1494: 
1495:   _g1h->update_parallel_gc_threads_cpu_time();
1496: 
1497:   policy->record_concurrent_mark_remark_end();
1498: }
